func (e *Executor) buildDefaultFileContent(name string) string {
	if name == "" {
		name = "document"
	}
	safeName := strings.TrimSpace(name)
	safeName = strings.TrimSuffix(safeName, ".")
	return "# " + safeName + "\n\nGenerated by Aetox."
}

func (e *Executor) executeTool(ctx context.Context, name string, args map[string]any) (skill.Output, bool, error) {
	name = strings.TrimSpace(name)
	if name == "" {
		return skill.Output{}, false, errors.New("tool call has empty function name")
	}

	if e.dispatcher == nil {
		return skill.Output{}, false, errors.New("tool dispatcher is not available")
	}

	assessment := safety.AssessCommand(name, toolCallToArgs(name, args))
	if assessment.Risk == safety.RiskHigh {
		commandLine := name
		for _, rawArg := range toolCallToArgs(name, args) {
			if rawArg == "" {
				continue
			}
			commandLine += " " + rawArg
		}
		ok, confirmErr := e.approveOrDeny(ctx, commandLine, assessment.Reason)
		if confirmErr != nil {
			return skill.Output{}, true, confirmErr
		}
		if !ok {
			return skill.Output{
				Name:       name,
				Content:    "tool execution blocked by user",
				RawOutput:  "tool execution blocked by user",
				Success:    false,
				Stderr:     "tool execution blocked by user",
				DurationMs: 0,
			}, true, nil
		}
	}

	output, handled, err := e.dispatcher.ExecuteTool(ctx, name, args)
	if !handled {
		return output, false, fmt.Errorf("tool %q is not exposed to agent", name)
	}
	return output, true, err
}

func toolCallToArgs(name string, args map[string]any) []string {
	name = strings.ToLower(strings.TrimSpace(name))
	switch name {
	case "write":
		path := ""
		content := ""
		if raw, ok := args["path"].(string); ok {
			path = strings.TrimSpace(raw)
		}
		if raw, ok := args["content"].(string); ok {
			content = strings.TrimSpace(raw)
		}
		result := make([]string, 0, 2)
		if path != "" {
			result = append(result, path)
		}
		if content != "" {
			result = append(result, content)
		}
		return result
	case "list":
		if raw, ok := args["path"].(string); ok {
			return []string{strings.TrimSpace(raw)}
		}
	case "read", "delete":
		if raw, ok := args["path"].(string); ok {
			return []string{strings.TrimSpace(raw)}
		}
	case "github_repo_summary", "plugin_install":
		if raw, ok := args["repo_url"].(string); ok {
			return []string{strings.TrimSpace(raw)}
		}
	}
	return nil
}

func (e *Executor) approveOrDeny(ctx context.Context, name, reason string) (bool, error) {
	if e.approve == nil {
		return true, nil
	}
	return e.approve(ctx, name, reason)
}

func (e *Executor) normalizeIntent(line string, intent command.Intent) command.Intent {
	if intent.Raw != "" {
		return intent
	}
	return command.Parse(line, command.ParseTokens, e.commandSet)
}

func (e *Executor) summarizeToolExecution(
	ctx context.Context,
	originalInput string,
	result skill.Output,
	status TurnStatus,
	execErr error,
) (string, error) {
	output := strings.TrimSpace(result.RawOutput)
	if output == "" {
		output = strings.TrimSpace(result.Content)
	}
	output = e.sanitizeAndTrimOutput(output)
	if output == "(no output)" || output == "" {
		output = e.inferredToolFallbackOutput(result.Name, result.Command, status, execErr, result.Stderr)
	}

	commandLine := strings.TrimSpace(result.Command)
	if commandLine == "" {
		commandLine = result.Name
	}

	errorLine := ""
	if strings.TrimSpace(result.Stderr) != "" {
		errorLine = fmt.Sprintf("\nTool error: %s", result.Stderr)
	} else if execErr != nil {
		errorLine = fmt.Sprintf("\nTool error: %s", execErr.Error())
	}

	summaryPrompt := fmt.Sprintf(
		"Original user request: %q\n"+
			"Tool: %s\n"+
			"Command: %s\n"+
			"Execution status: %s\n"+
			"DurationMs: %d\n"+
			"Output:\n%s\n%s\n\n"+
			"Respond in the same language as the user and be concise.\n"+
			"Start with an explicit status phrase for executed (%s), then summarize key result and mention completion.",
		originalInput,
		result.Name,
		commandLine,
		status,
		result.DurationMs,
		output,
		errorLine,
		status,
	)

	summaryCtx, cancel := context.WithTimeout(ctx, e.summaryTimeout)
	defer cancel()
	summary, err := e.agent.Respond(summaryCtx, summaryPrompt, e.turnOptions)
	if err != nil {
		return "", err
	}

	summary = strings.TrimSpace(summary)
	if strings.Contains(summary, "Start with an explicit status phrase") ||
		strings.Contains(summary, "Original user request:") {
		return "", errors.New("provider did not generate a concise summary")
	}
	if summary == "" {
		return "", errors.New("empty summary response")
	}
	if len(summary) > e.summaryLimit {
		summary = summary[:e.summaryLimit] + "\n...(output truncated)"
	}
	return summary, nil
}

func (e *Executor) fallbackToolSummary(result skill.Output, status TurnStatus, execErr error) string {
	output := strings.TrimSpace(result.RawOutput)
	if output == "" {
		output = strings.TrimSpace(result.Content)
	}
	if output == "" {
		output = e.inferredToolFallbackOutput(result.Name, result.Command, status, execErr, result.Stderr)
	}
	output = e.sanitizeAndTrimOutput(output)
	stderr := strings.TrimSpace(result.Stderr)
	if status == TurnStatusError && stderr != "" && !strings.Contains(output, stderr) {
		output = fmt.Sprintf("%s\nError: %s", output, stderr)
	} else if execErr != nil && stderr == "" {
		output = fmt.Sprintf("%s\nError: %s", output, execErr.Error())
	}

	prefix := "executed (done)"
	switch status {
	case TurnStatusError:
		prefix = "executed (error)"
	case TurnStatusBlocked:
		prefix = "executed (blocked)"
	}
	commandText := strings.TrimSpace(result.Command)
	if commandText != "" {
		commandText = fmt.Sprintf("command: %s. ", commandText)
	}
	return fmt.Sprintf("%s. %s%s", prefix, commandText, output)
}

func (e *Executor) inferredToolFallbackOutput(
	commandName string,
	command string,
	status TurnStatus,
	execErr error,
	stderr string,
) string {
	name := strings.ToLower(strings.TrimSpace(commandName))
	command = strings.TrimSpace(command)
	trimmedErr := strings.TrimSpace(stderr)
	switch name {
	case "list":
		if status == TurnStatusError {
			if trimmedErr != "" {
				return "list failed: " + trimmedErr
			}
			if execErr != nil {
				return "list failed: " + strings.TrimSpace(execErr.Error())
			}
			return "list failed for " + command + " (no output)"
		}
		if command == "" {
			return "list completed with no output"
		}
		return "list completed with no output for " + command
	default:
		if status == TurnStatusError {
			if trimmedErr != "" {
				return trimmedErr
			}
			if execErr != nil {
				return strings.TrimSpace(execErr.Error())
			}
			return "command completed with no output"
		}
		return "command completed with no output"
	}
}

func (e *Executor) sanitizeAndTrimOutput(output string) string {
	output = strings.TrimSpace(output)
	if output == "" {
		return "(no output)"
	}

	redactionRules := map[string]*regexp.Regexp{
		"api key":  regexp.MustCompile("(?i)(api key\\s*[:=]\\s*)[^\\s]+"),
		"token":    regexp.MustCompile("(?i)(token\\s*[:=]\\s*)[^\\s]+"),
		"password": regexp.MustCompile("(?i)(password\\s*[:=]\\s*)[^\\s]+"),
	}
	for _, re := range redactionRules {
		output = re.ReplaceAllString(output, "$1[REDACTED]")
	}

	if len(output) > e.summaryLimit {
		output = output[:e.summaryLimit] + "\n...(output truncated)"
	}
	return output
}

func (e *Executor) normalizeToolResult(result skill.Output) skill.Output {
	output := strings.TrimSpace(result.RawOutput)
	if output == "" {
		output = strings.TrimSpace(result.Content)
	}
	output = e.sanitizeAndTrimOutput(output)
	result.Content = output
	result.RawOutput = output
	return result
}

func (e *Executor) dispatchBySkill(ctx context.Context, line string) (skill.Output, bool, error) {
	if e.dispatcher == nil {
		return skill.Output{}, false, nil
	}
	output, handled, err := e.dispatcher.Execute(ctx, line)
	if !handled || err != nil {
		return output, handled, err
	}
	return output, true, nil
}

func (e *Executor) newToolResultForTurn(name, command, detail string) skill.Output {
	if strings.TrimSpace(name) == "" {
		name = "tool"
	}
	detail = strings.TrimSpace(detail)
	if detail == "" {
		detail = "(no output)"
	}
	return skill.Output{
		Name:       name,
		Command:    command,
		Content:    detail,
		RawOutput:  detail,
		Success:    false,
		Stderr:     detail,
		DurationMs: 0,
	}
}

func asStreamHandler(callback func(string)) func(string) error {
	if callback == nil {
		return nil
	}
	return func(chunk string) error {
		callback(chunk)
		return nil
	}
}
